export type RemoteShopData = {
	description: string;
	id: number;
	image: string;
	link: string;
	name: string;
	rating: any;
	recensionCount: any; // Yes, this one field does have different naming convention on the remote than all the others
	seo_name: string;
};

export type ShopData = {
	description: string;
	id: number;
	image: string;
	link: string;
	name: string;
	rating: number;
	recensionCount: number;
	seoName: string;
};

export function normalizeShop(shop: RemoteShopData): ShopData {
	return {
		description: shop.description,
		id: shop.id,
		image: shop.image,
		link: shop.link,
		name: shop.name,
		rating: shop.rating,
		recensionCount: shop.recensionCount,
		seoName: shop.seo_name,
	};
}
