import { normalizeShop, type ShopData } from 'service/shop/model';
import { createAPIMethod } from 'utils/generic';

export type GetShopParams = { id: string };
export type GetShopResponse = ShopData;

/**
 * Get shop tied with unpacked offers by its ID
 */
export async function getShop(params: GetShopParams, headers?: HeadersInit) {
	return createAPIMethod<object, GetShopResponse>({
		path: `/zbozi/unpacked/shop/${params.id}`,
		method: 'GET',
		normalize: ({ result }) => normalizeShop(result),
		headers,
		useCache: true,
	})();
}

export async function suggestShopUrl() {
	return createAPIMethod<object, string>({
		path: `/users/self/shop_url/suggest`,
		method: 'GET',
		normalize: ({ result }) => result.shop_url,
		useCache: true,
	})();
}

export async function validateShopUrl(url: string) {
	return createAPIMethod<object, boolean>({
		path: `/users/self/shop_url/validate?shop_url=${encodeURIComponent(url)}`,
		method: 'GET',
		normalize: ({ result }) => result.is_same_as_login,
		useCache: false,
	})();
}
